import numpy as np


def sigmoid(z):
    """Numerically stable sigmoid (clamps z to avoid exp overflow)."""
    z = np.clip(z, -500.0, 500.0)
    return 1.0 / (1.0 + np.exp(-z))


def forward_pass(layers, x):
    """Run a forward pass through a multi-layer network."""
    a = np.asarray(x, dtype=float)
    for layer in layers:
        W = np.asarray(layer["W"], dtype=float)
        b = np.asarray(layer["b"], dtype=float)
        if W.shape[1] != a.shape[0]:
            raise ValueError(
                f"shape mismatch: W has {W.shape[1]} columns "
                f"but input has {a.shape[0]} elements"
            )
        z = W @ a + b
        a = sigmoid(z)
    return a
